import{_ as o,o as s,c as t,a2 as i}from"./chunks/framework.DvFsUg-r.js";const u=JSON.parse('{"title":"Hexo 블로그 콘텐츠 임포트 자동화","description":"","frontmatter":{"title":"Hexo 블로그 콘텐츠 임포트 자동화","feature_id":"008","status":"done","created":"2026-06-02 14:57 (KST)","date":"2026-06-02T00:00:00.000Z","tags":["tooling","content-migration","hexo","vitepress","automation"]},"headers":[],"relativePath":"specs/008-hexo-blog-import/spec.md","filePath":"specs/008-hexo-blog-import/spec.md","lastUpdated":null}'),r={name:"specs/008-hexo-blog-import/spec.md"};function c(a,e,d,n,l,g){return s(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="spec-hexo-블로그-콘텐츠-임포트-자동화" tabindex="-1">Spec: Hexo 블로그 콘텐츠 임포트 자동화 <a class="header-anchor" href="#spec-hexo-블로그-콘텐츠-임포트-자동화" aria-label="Permalink to &quot;Spec: Hexo 블로그 콘텐츠 임포트 자동화&quot;">​</a></h1><h2 id="why-문제-목적" tabindex="-1">Why (문제 / 목적) <a class="header-anchor" href="#why-문제-목적" aria-label="Permalink to &quot;Why (문제 / 목적)&quot;">​</a></h2><p><code>../coffeeman1-main</code> 에는 Hexo 로 운영하던 기존 블로그의 모든 글·이미지·자료가 남아 있다(게시글 약 100여 편, 이미지 수백 장). 이 콘텐츠를 현재 VitePress 사이트(<code>blog/blog/</code>)로 옮겨 한 곳에서 함께 게시·검색·관리하고 싶다.</p><p>문제는 두 시스템의 형식이 다르다는 점이다.</p><ul><li><strong>프런트매터</strong>: Hexo 는 <code>title</code> + <code>date</code>(<code>YYYY-MM-DD HH:MM:SS</code>) 중심이고, VitePress 빌드는 깨진 내부 링크·Vue 템플릿 충돌(<code>{{ }}</code>)에 민감하다.</li><li><strong>이미지 참조</strong>: Hexo 는 글별 asset 폴더와 전역 <code>source/images/</code> 를 섞어 쓰고, 본문에서 <code>../../images/foo.jpg</code> 같은 상대경로로 가리킨다. VitePress 에서는 이 경로가 그대로는 깨진다.</li><li><strong>분류 구조</strong>: <code>source/_posts/</code> 아래 <code>coding/{java,jhipster,...}</code>, <code>setup</code>, <code>tool</code> 등 폴더로 카테고리가 표현돼 있다.</li></ul><p>이걸 한 번 손으로 옮기는 것은 실수가 잦고 재현이 안 된다. 이미 이 저장소에는 명세를 사이트로 동기화하는 <code>scripts/sync-specs-to-vitepress.*</code> 와 vugrid 를 동기화하는 <code>scripts/sync-vugrid.*</code> 같은 <strong>반복 실행 가능한 임포트 스크립트</strong> 선례가 있다. 같은 방식으로, <strong>원본을 건드리지 않고 한 번의 명령으로 전체 콘텐츠를 VitePress 섹션으로 변환·복사하는 자동화 스크립트</strong>가 필요하다.</p><h2 id="clarifications" tabindex="-1">Clarifications <a class="header-anchor" href="#clarifications" aria-label="Permalink to &quot;Clarifications&quot;">​</a></h2><h3 id="session-2026-06-02" tabindex="-1">Session 2026-06-02 <a class="header-anchor" href="#session-2026-06-02" aria-label="Permalink to &quot;Session 2026-06-02&quot;">​</a></h3><ul><li>Q: 이미지가 아닌 Hexo 전용 태그(<code>{% fa %}</code> 72개, <code>{% callout %}</code> 11쌍, <code>{% drawio %}</code> 3개, <code>{% iframe %}</code> 1개)를 어떻게 변환할까? → A: VitePress 등가물로 변환한다 (<code>{% fa %}</code>→인라인 아이콘/이모지, <code>{% callout %}</code>→VitePress 컨테이너 <code>::: tip/warning</code>, <code>{% iframe %}</code>→<code>&lt;iframe&gt;</code>, <code>{% drawio %}</code>→이미지/링크). 시각적 의도를 최대한 보존.</li><li>Q: <code>{% asset_img foo.png %}</code> 와 <code>{% include %}</code>(공용 조각 16곳)는 어떻게 처리할까? → A: <code>{% asset_img %}</code>는 복사한 이미지를 가리키는 표준 마크다운 이미지(<code>![](경로)</code>)로 재작성하고, <code>{% include %}</code>는 참조 대상 조각의 내용을 그 자리에 인라인으로 펼쳐 넣어 의존성을 제거한다.</li><li>Q: 한글 메뉴/카테고리 구성은 어떻게 넘길까? → A: 메뉴(사이드바/내비)는 Hexo 폴더·<code>categories</code> 구조를 그대로 그룹으로 삼아 자동 생성하되, <strong>라벨은 영문으로 통일</strong>한다(한글 카테고리는 영문으로 변환·표기).</li></ul><h2 id="what-범위" tabindex="-1">What (범위) <a class="header-anchor" href="#what-범위" aria-label="Permalink to &quot;What (범위)&quot;">​</a></h2><h3 id="포함" tabindex="-1">포함 <a class="header-anchor" href="#포함" aria-label="Permalink to &quot;포함&quot;">​</a></h3><ul><li><code>../coffeeman1-main/source/_posts/</code> 의 모든 게시글(<code>.md</code>)을 VitePress 사이트의 새 섹션(예: <code>/blog-archive/</code> 또는 <code>/hexo/</code>)으로 변환·복사한다.</li><li>Hexo 프런트매터를 VitePress 가 받아들이는 형태로 정규화한다(제목·작성일· 태그/카테고리 보존, 정렬은 본 저장소 규칙대로 <strong>최신 먼저</strong>).</li><li>글이 참조하는 이미지를 모두 찾아 사이트의 정적 자산 위치로 복사하고, 본문 이미지 링크(<code>{% asset_img %}</code> 포함)를 표준 마크다운 이미지로 재작성한다.</li><li>이미지가 아닌 Hexo 전용 태그(<code>{% fa %}</code>, <code>{% callout %}</code>, <code>{% include %}</code>, <code>{% drawio %}</code>, <code>{% iframe %}</code>)를 VitePress 등가 표현으로 변환하거나 인라인 전개한다.</li><li>Hexo 의 폴더 기반 카테고리 구조(coding/java 등)와 <code>categories</code> 를 그룹으로 삼아 메뉴를 자동 생성하되, <strong>메뉴 라벨은 영문으로 통일</strong>한다.</li><li>새 섹션의 진입 인덱스(<code>index.md</code>)와 사이드바·상단 내비게이션 항목을 생성/등록해, 기존 cowork·hermes 섹션과 같은 방식으로 노출한다.</li><li>변환 결과가 VitePress <strong>strict 빌드</strong>(<code>npm run build</code>)를 깨지 않게 한다 (깨진 내부 링크 0, <code>{{ }}</code> 등 Vue 템플릿 충돌 회피).</li><li>스크립트는 <strong>재실행 가능(idempotent)</strong> 해야 한다 — 다시 돌려도 중복·찌꺼기 없이 같은 결과가 나온다.</li><li>실행 후 요약 리포트를 출력한다(변환된 글 수, 복사된 이미지 수, 건너뛴/실패 항목과 사유).</li></ul><h3 id="제외-non-goals" tabindex="-1">제외 (Non-goals) <a class="header-anchor" href="#제외-non-goals" aria-label="Permalink to &quot;제외 (Non-goals)&quot;">​</a></h3><ul><li>원본 Hexo 저장소(<code>../coffeeman1-main</code>)를 수정하지 않는다(읽기 전용 소스).</li><li>Hexo 테마·레이아웃·플러그인·<code>db.json</code>(렌더 캐시)·검증용 HTML(<code>google*.html</code>, <code>naver*.html</code>)·<code>robots.txt</code>·<code>ads.txt</code>·<code>quasar/</code>(skip_render) 등 <strong>글 본문이 아닌 자산</strong>은 옮기지 않는다.</li><li>옛 URL(<code>:title/</code> permalink)에서 새 경로로의 영구 리다이렉트(301) 구성은 이번 범위 밖이다(필요 시 후속 작업).</li><li>글 내용 자체의 교정·재작성·번역은 하지 않는다(형식 변환만).</li><li>댓글·조회수·SEO 메타 등 런타임 데이터 이전은 다루지 않는다.</li></ul><h2 id="user-scenarios" tabindex="-1">User Scenarios <a class="header-anchor" href="#user-scenarios" aria-label="Permalink to &quot;User Scenarios&quot;">​</a></h2><ol><li><strong>As a</strong> 저장소 관리자, <strong>I want</strong> 한 번의 명령으로 기존 Hexo 블로그 전체를 VitePress 사이트에 임포트, <strong>so that</strong> 두 사이트를 따로 운영하지 않고 한 곳에서 모든 글을 게시·관리할 수 있다.</li><li><strong>As a</strong> 관리자, <strong>I want</strong> 스크립트를 다시 실행해도 안전하게 결과가 갱신되기를, <strong>so that</strong> 원본에 글을 추가한 뒤 재동기화할 수 있다.</li><li><strong>As a</strong> 독자, <strong>I want</strong> 임포트된 글의 이미지와 링크가 정상 표시되기를, <strong>so that</strong> 옮겨온 글도 원본과 동일하게 읽을 수 있다.</li><li><strong>As a</strong> 관리자, <strong>I want</strong> 실행 후 무엇이 옮겨졌고 무엇이 실패했는지 요약을 보기를, <strong>so that</strong> 누락이나 깨진 변환을 바로 확인할 수 있다.</li></ol><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><ul><li><strong>FR-1</strong>: 스크립트는 소스 경로(기본 <code>../coffeeman1-main</code>)의 모든 게시글을 발견하여 처리한다. 처리 대상은 <code>source/_posts/</code> 하위 모든 <code>.md</code> 파일이다.</li><li><strong>FR-2</strong>: 각 글의 Hexo 프런트매터를 읽어 VitePress 호환 프런트매터로 변환한다. 최소한 제목과 작성일시를 보존하고, 카테고리/태그가 있으면 옮긴다.</li><li><strong>FR-3</strong>: 본 저장소 문서 규칙에 따라 작성일시를 보존하고, 목록·인덱스는 <strong>최신(작성일 내림차순) 먼저</strong>로 정렬한다.</li><li><strong>FR-4</strong>: 글이 참조하는 모든 이미지를 해석하여(글별 asset 폴더, 전역 <code>images/</code>·<code>img/</code>, <code>../../images/...</code> 상대경로, Hexo <code>{% asset_img %}</code> 태그 261곳 포함) 사이트의 정적 자산 위치로 복사하고, 본문 링크를 VitePress 에서 작동하는 <strong>표준 마크다운 이미지</strong>(<code>![](경로)</code>)로 재작성한다.</li><li><strong>FR-5</strong>: 이미지·링크 해석에 실패한 항목(원본 부재 등)은 빌드를 깨지 않도록 처리하고, 실패 목록을 리포트에 남긴다.</li><li><strong>FR-6</strong>: Hexo 폴더 기반 분류 구조와 <code>categories</code> 프런트매터를 그룹 단위로 삼아 사이트 섹션의 메뉴(사이드바·내비)를 자동 생성하되, <strong>모든 메뉴 라벨은 영문으로 통일</strong>한다(한글 카테고리는 영문으로 변환·표기).</li><li><strong>FR-7</strong>: 변환 결과가 VitePress strict 빌드를 통과한다 — 깨진 내부 링크 0, Vue 템플릿 해석 충돌(<code>{{ }}</code>, 처리되지 않은 인라인 코드 등)로 인한 빌드 실패 0.</li><li><strong>FR-8</strong>: 새 섹션의 진입 <code>index.md</code> 와 사이드바·상단 내비게이션을 생성/등록하여 기존 섹션(cowork·hermes)과 동일한 방식으로 콘텐츠가 노출된다.</li><li><strong>FR-13</strong>: 이미지가 아닌 Hexo 전용 태그를 VitePress 등가 표현으로 변환한다 — <code>{% fa %}</code>(Font Awesome 아이콘)→인라인 아이콘/이모지, <code>{% callout %}…{% endcallout %}</code>→VitePress 컨테이너(<code>::: tip</code>/<code>::: warning</code> 등), <code>{% iframe %}</code>→ <code>&lt;iframe&gt;</code>, <code>{% drawio %}</code>→이미지 또는 링크. 시각적 의도를 최대한 보존한다.</li><li><strong>FR-14</strong>: Hexo <code>{% include %}</code>(공용 조각 삽입, 16곳)는 참조 대상 조각의 내용을 해당 위치에 인라인으로 펼쳐 넣어 외부 의존성을 제거한다. 참조 대상을 찾지 못하면 빌드를 깨지 않게 처리하고 실패 목록에 남긴다.</li><li><strong>FR-15</strong>: 변환되지 않은 잔여 Hexo 태그(<code>{% ... %}</code>)가 출력물에 남지 않는다 — 알려진 태그는 모두 등가 변환하거나 안전하게 제거하며, 미처리 태그는 리포트에 집계한다.</li><li><strong>FR-9</strong>: 스크립트는 재실행 가능(idempotent)하다. 재실행 시 이전 산출물을 안전하게 갱신하며, 중복 파일이나 고아 자산을 남기지 않는다.</li><li><strong>FR-10</strong>: 실행 종료 시 요약 리포트를 출력한다(변환된 글 수, 복사된 이미지 수, 건너뛴·실패 항목과 사유).</li><li><strong>FR-11</strong>: 원본 소스 디렉터리는 읽기 전용으로 취급하며 어떤 파일도 수정·삭제하지 않는다.</li><li><strong>FR-12</strong>: 기존 동기화 스크립트(<code>scripts/sync-*.{ps1,sh}</code>)와 일관된 위치·호출 방식으로 제공하여, 빌드 파이프라인/기여자가 동일한 흐름으로 실행할 수 있다.</li></ul><h2 id="key-entities" tabindex="-1">Key Entities <a class="header-anchor" href="#key-entities" aria-label="Permalink to &quot;Key Entities&quot;">​</a></h2><ul><li><strong>소스 게시글(Source Post)</strong>: Hexo <code>source/_posts/</code> 의 <code>.md</code> 파일. 프런트매터 (제목·작성일·카테고리·태그)와 본문, 연관 이미지 자산을 가진다.</li><li><strong>이미지 자산(Image Asset)</strong>: 글별 asset 폴더 또는 전역 <code>images/</code>·<code>img/</code> 의 파일. 본문에서 상대경로로 참조된다.</li><li><strong>임포트 섹션(Imported Section)</strong>: 변환 결과가 들어갈 VitePress 사이트의 새 최상위 섹션(인덱스 + 글 + 사이드바 + 내비 항목).</li><li><strong>임포트 리포트(Import Report)</strong>: 1회 실행 결과 요약(처리/복사/실패 집계).</li></ul><h2 id="success-criteria" tabindex="-1">Success Criteria <a class="header-anchor" href="#success-criteria" aria-label="Permalink to &quot;Success Criteria&quot;">​</a></h2><ul><li><strong>SC-1</strong>: 단일 명령 한 번으로 소스의 모든 게시글이 VitePress 사이트에 나타난다 (수동 파일 편집 0건).</li><li><strong>SC-2</strong>: 변환 직후 <code>npm run build</code>(strict)가 성공한다 — 깨진 내부 링크·템플릿 충돌로 인한 실패 0건.</li><li><strong>SC-3</strong>: 임포트된 글에서 표본 검수 시 이미지 표시율 100%(원본에 존재하는 이미지 기준), 깨진 이미지 0건.</li><li><strong>SC-4</strong>: 스크립트를 연속 2회 실행해도 사이트 산출물이 동일하다(중복·고아 파일 0건) — 재실행 안전성 확인.</li><li><strong>SC-5</strong>: 새 섹션이 상단 내비게이션과 사이드바에서 접근 가능하며(메뉴 라벨은 영문), 글 목록이 최신 먼저로 정렬된다.</li><li><strong>SC-8</strong>: 출력된 마크다운에 변환되지 않은 Hexo 태그(<code>{% ... %}</code>)가 0건 남는다.</li><li><strong>SC-6</strong>: 실행 후 리포트로 처리 건수와 실패 항목을 즉시 확인할 수 있어, 누락 여부를 추가 조사 없이 판단할 수 있다.</li><li><strong>SC-7</strong>: 원본 <code>../coffeeman1-main</code> 의 모든 파일이 실행 전후로 변경되지 않는다.</li></ul><h2 id="assumptions" tabindex="-1">Assumptions <a class="header-anchor" href="#assumptions" aria-label="Permalink to &quot;Assumptions&quot;">​</a></h2><ul><li>소스 블로그의 글 본문은 Markdown 이며, 일부 글은 인라인 HTML/<code>&lt;style&gt;</code> 블록을 포함한다(예: 달력 글). 이런 인라인 마크업은 보존하되, VitePress(Vue) 가 해석하다 빌드를 깨는 패턴(<code>{{ }}</code> 등)만 안전하게 회피·이스케이프한다.</li><li>새 섹션 경로명은 구현 시 확정한다(가칭 <code>/blog-archive/</code>). 기존 섹션과 충돌하지 않는 단일 최상위 경로를 사용한다.</li><li>카테고리/태그가 비어 있는 글은 영문 라벨 &quot;Uncategorized&quot; 그룹으로 처리한다 (Hexo <code>default_category: uncategorized</code> 관례 준수).</li><li>한글 카테고리→영문 라벨 매핑은 구현 시 명시적 매핑표로 관리한다(예: 코딩→ Coding, 설치→Setup). 매핑이 없는 값은 원문을 음역/영문화한다.</li><li>구현 언어는 <strong>Node ESM 단일 스크립트</strong>(의존 0)다. 복잡한 텍스트 변환 때문에 PowerShell+Bash 페어 대신 채택했다(근거: <a href="./research">plan/research</a> R1). 얇은 <code>.ps1</code>/<code>.sh</code> 래퍼만 선례 일관성을 위해 둔다.</li><li>이미지 파일명 충돌은 글별 네임스페이스(폴더 분리)로 회피한다.</li><li>생성물 <code>blog/blog-archive/**</code> 는 <strong>커밋</strong>되어 CI 가 소비한다 — 임포터는 원본 <code>../coffeeman1-main</code> 을 읽으므로 CI(빌드)에서는 실행되지 않는다.</li></ul><h2 id="open-questions-해소됨" tabindex="-1">Open Questions (해소됨) <a class="header-anchor" href="#open-questions-해소됨" aria-label="Permalink to &quot;Open Questions (해소됨)&quot;">​</a></h2><ul><li>[x] 새 섹션의 노출 형태 → <strong><code>/blog-archive/</code> 경량 아카이브 인덱스</strong>(hero 없이 카테고리 그룹 + 최신글). <a href="./research">research.md</a> R2.</li><li>[x] 옛 Hexo URL(<code>:title/</code>) 리다이렉트 → <strong>이번 범위 밖</strong>으로 확정(보류). 옛 사이트로의 외부화로 대체. <a href="./research">research.md</a> R3.</li></ul>',26)])])}const m=o(r,[["render",c]]);export{u as __pageData,m as default};
